package hooks

import (
	"context"
	"fmt"

	"github.com/openmeterio/openmeter/openmeter/billing"
	"github.com/openmeterio/openmeter/openmeter/customer"
	"github.com/openmeterio/openmeter/pkg/models"
)

type (
	BillingValidatorHook     = models.ServiceHook[customer.Customer]
	NoopBillingValidatorHook = models.NoopServiceHook[customer.Customer]
)

var _ models.ServiceHook[customer.Customer] = (*billingValidatorHook)(nil)

type billingValidatorHook struct {
	NoopBillingValidatorHook
	billingService billing.Service
}

type BillingValidatorHookConfig struct {
	BillingService billing.Service
}

func (c BillingValidatorHookConfig) Validate() error {
	if c.BillingService == nil {
		return fmt.Errorf("billing service is required")
	}
	return nil
}

func NewBillingValidatorHook(config BillingValidatorHookConfig) (BillingValidatorHook, error) {
	if err := config.Validate(); err != nil {
		return nil, fmt.Errorf("invalid billing validator hook config: %w", err)
	}
	return &billingValidatorHook{billingService: config.BillingService}, nil
}

func (h *billingValidatorHook) PreDelete(ctx context.Context, cus *customer.Customer) error {
	// Check for open invoices via billing service
	// Return models.NewGenericValidationError if conditions not met
	return nil
}
